// Compare 'modified' timestamp with last known value.
// If changed, extract DSE schedule table rows from rendered HTML.

const data = $input.first().json;
const staticData = $getWorkflowStaticData('global');

const currentModified = data.modified || '';
const lastModified = staticData.lastModified || '';

// No change — stop execution
if (currentModified === lastModified && lastModified !== '') {
  return [];
}

// Page has changed (or first run) — update stored timestamp
staticData.lastModified = currentModified;

const html = (data.content && data.content.rendered) || '';
const pageUrl = (data.link) || 'https://cetcell.mahacet.org/cap-_2026-27/';

// ─── Try to parse a schedule table ─────────────────────────────────────────
// CET Cell typically uses: <table><tr><td>Activity</td><td>Dates</td></tr>...</table>
// We look for rows after any DSE-related heading.

const scheduleRows = [];

// Find <table> elements in the HTML
const tableRegex = /<table[^>]*>([\s\S]*?)<\/table>/gi;
let tableMatch;
const allTables = [];
while ((tableMatch = tableRegex.exec(html)) !== null) {
  allTables.push(tableMatch[1]);
}

// Look for a table that has date-like content (day/month patterns)
const datePattern = /\d{1,2}[\s\/\-](?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec|\d{2})[\s\/\-]\d{2,4}/i;

for (const tableHtml of allTables) {
  if (!datePattern.test(tableHtml)) continue;

  // Extract rows
  const rowRegex = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
  let rowMatch;
  let sortOrder = 0;

  while ((rowMatch = rowRegex.exec(tableHtml)) !== null) {
    const rowHtml = rowMatch[1];
    // Extract cell text
    const cells = [];
    const cellRegex = /<t[dh][^>]*>([\s\S]*?)<\/t[dh]>/gi;
    let cellMatch;
    while ((cellMatch = cellRegex.exec(rowHtml)) !== null) {
      const cellText = cellMatch[1].replace(/<[^>]+>/g, '').replace(/&amp;/g, '&').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
      cells.push(cellText);
    }

    if (cells.length >= 2 && cells[0] && !cells[0].match(/^(sr\.?\s*no|activity|particulars|dates?)$/i)) {
      scheduleRows.push({
        activity: cells[0],
        date_display: cells[1] || '',
        start_date: cells[2] || '',
        end_date: cells[3] || '',
        link: null,
        status: 'tba',
        sort_order: sortOrder++,
        source_url: pageUrl,
        scraped_at: new Date().toISOString()
      });
    }
  }

  if (scheduleRows.length > 0) break;
}

// ─── Check for DSE-specific content ─────────────────────────────────────────
const dseIndex = html.toLowerCase().indexOf('direct second year');
const hasDseContent = dseIndex !== -1;
const dseExcerpt = hasDseContent
  ? html.slice(Math.max(0, dseIndex - 50), dseIndex + 400).replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim()
  : 'No DSE-specific content found yet.';

return [{
  json: {
    changed: true,
    currentModified,
    lastModified: lastModified || '(first run)',
    pageUrl,
    scheduleRowsFound: scheduleRows.length,
    scheduleRows,
    hasDseContent,
    dseExcerpt: dseExcerpt.slice(0, 300)
  }
}];

// Upsert each schedule row into cap_dse_schedule.
// We DELETE existing rows first (full refresh), then INSERT new ones.
// Returns each row as a separate item for the HTTP Request node.
const rows = $input.first().json.scheduleRows;
return rows.map((row) => ({ json: row }));

// Prepare single Telegram message summarising what changed.
// Works for both cases: schedule found or just a content change.
const item = $input.first().json;

const schedFound = item.scheduleRowsFound > 0;
const lines = [
  `🚨 *CET Cell Page Updated*`,
  ``,
  `📅 Modified: \`${item.currentModified}\``,
  `(was: \`${item.lastModified}\`)`,
  ``,
  schedFound
    ? `✅ *${item.scheduleRowsFound} schedule rows extracted* and saved to Supabase.`
    : `⚠️ Page changed but no schedule table found yet.`,
  ``,
  item.hasDseContent ? `DSE excerpt:\n_${item.dseExcerpt}_` : `ℹ️ No DSE-specific content yet.`,
  ``,
  `🔗 ${item.pageUrl}`
];

return [{ json: { text: lines.join('\n') } }];
